   206→int 
   207→ldap_pvt_thread_join( ldap_pvt_thread_t thread, void **thread_return )
   208→{
   209→#if HAVE_PTHREADS < 7
   210→	void *dummy;
   211→	if (thread_return==NULL)
   212→	  thread_return=&dummy;
   213→#endif
   214→	return ERRVAL( pthread_join( thread, thread_return ) );
   215→}
